package com.example.oidc.config;

import com.example.oidc.security.OidcAuthorizationRequestResolver;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.registration.InMemoryClientRegistrationRepository;
import org.springframework.security.oauth2.core.AuthorizationGrantType;
import org.springframework.security.oauth2.core.ClientAuthenticationMethod;

@Configuration
public class OidcClientConfig {

    @Bean
    ClientRegistrationRepository clientRegistrationRepository(
            @Value("${app.oidc.registration-id:custom-oidc}") String registrationId,
            @Value("${app.oidc.client-id}") String clientId,
            @Value("${app.oidc.client-secret}") String clientSecret,
            @Value("${app.oidc.redirect-uri:{baseUrl}/login/oauth2/code/{registrationId}}") String redirectUri,
            @Value("${app.oidc.scope:openid,profile,email}") String[] scopes,
            @Value("${app.oidc.authorization-uri}") String authorizationUri,
            @Value("${app.oidc.token-uri}") String tokenUri,
            @Value("${app.oidc.user-info-uri}") String userInfoUri,
            @Value("${app.oidc.jwk-set-uri}") String jwkSetUri,
            @Value("${app.oidc.issuer-uri}") String issuerUri,
            @Value("${app.oidc.user-name-attribute:sub}") String userNameAttribute
    ) {
        ClientRegistration registration = ClientRegistration.withRegistrationId(registrationId)
                .clientId(clientId)
                .clientSecret(clientSecret)
                .clientAuthenticationMethod(ClientAuthenticationMethod.CLIENT_SECRET_BASIC)
                .authorizationGrantType(AuthorizationGrantType.AUTHORIZATION_CODE)
                .redirectUri(redirectUri)
                .scope(scopes)
                .authorizationUri(authorizationUri)
                .tokenUri(tokenUri)
                .userInfoUri(userInfoUri)
                .jwkSetUri(jwkSetUri)
                .issuerUri(issuerUri)
                .userNameAttributeName(userNameAttribute)
                .authorizationUri(authorizationUri)
                .tokenUri(tokenUri)
                .build();
        return new InMemoryClientRegistrationRepository(registration);
    }

    @Bean
    OidcAuthorizationRequestResolver oidcAuthorizationRequestResolver(
            ClientRegistrationRepository clientRegistrationRepository,
            @Value("${app.oidc.authorization-base-uri:/oauth2/authorization}") String authorizationBaseUri
    ) {
        return new OidcAuthorizationRequestResolver(clientRegistrationRepository, authorizationBaseUri);
    }
}

package com.example.oidc.controller;

import com.example.oidc.session.UserSession;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public Map<String, Object> home(Authentication authentication, HttpSession session) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", authentication != null && authentication.isAuthenticated());
        response.put("sessionId", session.getId());
        Object userSession = session.getAttribute(UserSession.SESSION_KEY);
        response.put("userSession", userSession);
        if (authentication instanceof OAuth2AuthenticationToken token && token.getPrincipal() instanceof OidcUser oidcUser) {
            response.put("name", oidcUser.getFullName());
            response.put("claims", oidcUser.getClaims());
        }
        return response;
    }

    @GetMapping("/me")
    public Map<String, Object> me(Authentication authentication, HttpSession session) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("sessionId", session.getId());
        response.put("principal", authentication != null ? authentication.getName() : null);
        response.put("userSession", session.getAttribute(UserSession.SESSION_KEY));
        return response;
    }
}

